/* This is a simple C program that prints 'Hello, World!' to the console
   Let's break down this program:
   1. #include <stdio.h> - Includes the standard input/output library
   2. int main() - The main function where program execution begins
   3. printf() - Function to print text to console
   4. return 0 - Indicates successful program completion
*/

/* Program showing basic structure of C */

#include <stdio.h>   // Preprocessor command
#include <stdlib.h>

// Function declaration
void greet(char name[]);

int main() {         // Main function
    // Variable declaration
    int age = 25;
    char name[] = "John";

    // Function call
    greet(name);

    // Print age
    printf("Age: %d\n", age);

    return 0;
}

// Function definition
void greet(char name[]) {
    printf("Hello, %s!\n", name);
}

