#include <stdio.h>

int main() {
    int age = 25;           // Integer
    float height = 5.8;     // Floating point
    char grade = 'A';       // Character
    double pi = 3.14159;    // Double precision float

    printf("Age: %d\n", age);
    printf("Height: %.1f\n", height);
    printf("Grade: %c\n", grade);
    printf("Pi: %f\n", pi);

    return 0;
}

#include <stdio.h>

int main() {
    // Variable declaration
    int number;        // Declaration
    int count = 10;    // Declaration with initialization
    float price = 9.99;
    char letter = 'X';

    // Assigning value
    number = 5;

    // Using variables
    printf("Number: %d\n", number);
    printf("Count: %d\n", count);
    printf("Price: %.2f\n", price);
    printf("Letter: %c\n", letter);

    return 0;
}
